query:
SELECT
    name,
    property_name,
    address,
    property_status,
    risk_level,
    property_type,
    owner_name
FROM `tabAbandoned Property`
WHERE docstatus < 2
{% if filters.property_status %}
  AND property_status = %(property_status)s
{% endif %}
{% if filters.risk_level %}
  AND risk_level = %(risk_level)s
{% endif %}
{% if filters.property_type %}
  AND property_type = %(property_type)s
{% endif %}
ORDER BY modified DESC
